def convert():
    """Convert raw cookie string to Netscape format."""
    lines = ["# Netscape HTTP Cookie File", "# Generated by douyin_summarize", ""]

    # Default expiry: 60 days from now
    expiry = str(int(time.time()) + 60 * 86400)

    for pair in RAW_COOKIES.split(";"):
        pair = pair.strip()
        if not pair or "=" not in pair:
            continue

        name, value = pair.split("=", 1)
        name = name.strip()
        value = value.strip()

        if not name:
            continue

        # domain, include_subdomains, path, secure, expiry, name, value
        lines.append(f".douyin.com\tTRUE\t/\tFALSE\t{expiry}\t{name}\t{value}")

    return "\n".join(lines) + "\n"


if __name__ == "__main__":
    from pathlib import Path
    out = Path(__file__).parent / "cookies.txt"
    content = convert()
    out.write_text(content)
    count = len([l for l in content.strip().split("\n") if l and not l.startswith("#")])
    print(f"Written {count} cookies to {out}")
